import{_ as n,a as i}from"./chunks/wechat-group-qrcode.D7QkRNzJ.js";import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.Dcoxob_B.js";const b=JSON.parse('{"title":"OpenViking Team and Organization","description":"","frontmatter":{"_rawMarkdown":"# OpenViking Team and Organization\\n\\n## Project Overview\\n\\nOpenViking is an open-source context database initiated and maintained by ByteDance’s Volcano Engine Viking team, dedicated to building robust context engineering infrastructure for the AI Agent ecosystem. As a new-generation context database, OpenViking provides a unified data abstraction layer, an intelligent semantic parsing engine, and a high-performance hybrid retrieval system to deliver reliable backend support for all kinds of AI applications.\\n\\n## Team Introduction\\n\\n### Viking Team Background\\n\\nThe Viking team belongs to ByteDance’s Volcano Engine and focuses on unstructured information processing and intelligent retrieval. The team brings together dozens of seasoned experts across distributed systems, machine learning, data engineering, and AI algorithms, with extensive commercial experience in context engineering.\\n\\n#### Core Technical Capabilities\\n\\n**Large-Scale Vector Retrieval System**\\n- Supports real-time retrieval and similarity computation over hundreds of millions of vectors\\n- Delivers millisecond-level latency to meet high-concurrency business scenarios\\n- Supports hybrid retrieval strategies combining semantic similarity and keyword matching\\n\\n**Multimodal Content Understanding Engine**\\n- Supports intelligent parsing for text, images, audio, video, and more\\n- Achieves cross-modal semantic association and content understanding\\n- Provides unified content abstraction and semantic representation\\n\\n**Distributed System Architecture Design**\\n- Extensive experience building highly available, scalable distributed systems\\n- Supports elastic scaling and automatic failure recovery\\n- Balances data consistency and system performance\\n\\n### Development History and Technical Evolution\\n\\nThe Viking team’s exploration in context engineering reflects our commitment to continuous innovation and industry impact. As AI Agent applications rapidly evolve, we plan to use OpenViking as a public verification platform for new concepts and approaches, building in the open together with the community to create a responsible AI application stack.\\n\\n| Time Period | Milestone | Technical Breakthroughs and Industry Impact |\\n|-------------|-----------|---------------------------------------------|\\n| **2019–2023** | VikingDB vector database widely adopted inside ByteDance | Powered multiple core products’ unstructured information retrieval; accumulated engineering experience in large-scale vector retrieval; validated the technical value of vector databases in real-world business scenarios |\\n| **2024** | Released developer-facing product matrix: VikingDB, Viking Knowledge Base, Viking Memory Base | Officially provided on Volcano Engine public cloud; successfully supported thousands of enterprise customers building AI-native applications; marked the successful transition from internal tooling to commercial products |\\n| **2025** | Expanded to upper-layer applications such as AI Search and Knowledge Assistants | Built a complete product matrix from infrastructure to application layer; further validated business value across scenarios; formed a full loop from technology to product |\\n| **Late 2025** | Open-sourced [MineContext](https://github.com/volcengine/MineContext) project | Explored proactive AI application patterns; validated personal context engineering ideas; accumulated community operation experience for OpenViking |\\n| **Early 2026** | Open-sourced OpenViking project | Released a newly designed context database architecture for the global AI Agent ecosystem; marked the strategic shift from commercial product provider to open-source contributor |\\n\\n### Academic Collaboration and Industry–Academia Integration\\n\\nSince its inception, OpenViking has established deep academic collaborations with top universities and research institutes worldwide to jointly explore context database design paradigms and best engineering practices for the AI era. This industry–academia collaboration ensures technological advancement while staying closely aligned with real application needs.\\n\\nWe sincerely thank the following scholars for their contributions and guidance in launching OpenViking:\\n\\n- Associate Professor Sun Yahui, School of Information, Renmin University of China\\n- Professor Gao Yunjun, School of Software, Zhejiang University; Researchers Zhu Yifan and Ge Congcong\\n- Associate Professor Dai Guohao, School of Artificial Intelligence, Shanghai Jiao Tong University; Co‑founder and Chief Scientist of Wuwen Xinqiong\\n\\nOur collaboration models include:\\n- **Joint research projects**: conduct frontier research in context engineering\\n- **Technical workshops**: organize regular academic exchanges and technical reviews\\n- **Talent cultivation**: provide practice platforms and research topics for graduate students\\n- **Technology transfer**: transform academic findings into engineering best practices\\n\\n## Open-Source Organization\\n\\n### Project Development Stages\\n\\nOpenViking is currently in its early development stage. We divide development into three key phases:\\n\\n- Phase 1: Foundation building\\nFocus on constructing solid technical foundations after open-sourcing, including core protocols, interfaces, AI Agent facilities, and providing a reliable minimal implementation.\\n\\n- Phase 2: Ecosystem expansion\\nBuild a plugin ecosystem, support third-party feature extensions, drive deep integration with mainstream AI frameworks and tools, and extend enterprise-grade capabilities to meet large-scale deployment needs.\\n\\n- Phase 3: Industry adoption\\nEstablish industry technical standards and best practices, build certification systems and partner ecosystems, and promote broader real-world adoption of context engineering.\\n\\n### Governance Structure and Decision-Making\\n\\nBased on the project’s long-term roadmap, we are establishing a layered governance structure:\\n\\n#### Open-Source Governance Committee\\nOpenViking is guided by a professional governance committee responsible for overall strategic planning and technical decisions. The committee consists of core contributors and domain experts, with responsibilities including:\\n\\n**Strategic Planning**\\n- Define the long-term technical roadmap and vision\\n- Set release plans and feature priorities\\n- Evaluate the long-term impact of technical decisions on the ecosystem\\n\\n**Technical Governance**\\n- Establish and maintain code quality standards and engineering norms\\n- Review core architecture changes and major feature implementations\\n- Ensure sustainability and backward compatibility\\n\\n**Community Development**\\n- Define community development strategy and contributor growth paths\\n- Organize technical exchange activities and developer conferences\\n- Build incentive mechanisms and recognition systems\\n\\n**Ecosystem Collaboration**\\n- Establish technical cooperation with related open-source projects\\n- Promote integration and certification with commercial products\\n- Manage intellectual property and license compliance\\n\\n#### Committee Core Members\\nCurrent core members of the governance committee:\\nHaojie Qin, Jiahui Zhou, Linggang Wang, Maojia Sheng, Yaohui Sun\\n\\nTo ensure openness and diversity, we welcome eligible community contributors to join the committee through future nomination and election procedures.\\n\\n## Community Participation\\n\\n### Join the Community\\n\\nWe warmly invite developers worldwide to join the OpenViking community and co-build next-generation context engineering infrastructure. You can participate in the following ways:\\n\\n#### Instant Messaging\\n\\n##### Lark Group\\n\\nScan the QR code below to join the Lark group and communicate with the core development team in real time:\\n\\n![Join via Lark QR](/lark-group-qrcode.png)\\n\\n*Note: Please ensure you have installed the [Lark client](https://www.feishu.cn/) before joining.*\\n\\n##### WeChat Group\\n\\nScan the QR code below to add the assistant on WeChat, mention \\"OpenViking\\" and you will be invited to the WeChat group:\\n\\n![Join via WeChat QR](/wechat-group-qrcode.png)\\n\\n**Discord**\\n\\n[Join our Discord Server](https://discord.com/invite/eHvx8E9XF3)\\n\\n**X**\\n\\n[Follow us on X](https://x.com/openvikingai)\\n\\n### Ways to Participate\\n\\nWe provide multiple participation channels to meet different collaboration needs:\\n\\n#### 1. Code Contributions\\n- **Submit Issues**: report bugs, propose features, or discuss technical solutions\\n- **Submit Pull Requests**: contribute code improvements, documentation updates, or test cases\\n- **Code Review**: participate in reviews to improve code quality\\n\\n#### 2. Documentation Contributions\\n- **Improve documentation**: enhance user guides, API docs, or tutorials\\n- **Translation support**: help translate documentation into other languages\\n- **Example code**: provide usage examples and best practices\\n\\n#### 3. Community Support\\n- **Technical sharing**: share experiences and technical insights\\n- **Q&A**: help other developers solve usage problems\\n- **Ecosystem building**: promote integration of OpenViking with other open-source projects\\n\\n#### 4. Ecosystem Expansion\\n- **Plugin development**: develop third-party plugins or feature extensions\\n- **Integration adaptation**: drive deep integration with mainstream frameworks\\n- **Application cases**: share real-world adoption experiences\\n\\n## Discussion and Collaboration\\n\\n### Official Channels\\n\\n#### GitHub Platform\\n- **Issues**: feature suggestions, bug reports, and technical discussions\\n- **Pull Requests**: code contributions and documentation updates\\n- **Discussions**: design discussions and community exchange\\n\\n#### Repository\\n- **Main repository**: `https://github.com/volcengine/openviking`\\n- **Issue tracking**: `https://github.com/volcengine/openviking/issues`\\n\\n### Real-Time Communication\\n\\n#### Lark Group\\n- **Technical discussion**: real-time technical exchange and Q&A\\n- **Code review**: fast feedback and collaborative development\\n- **Event notice**: community activities and technical sharing\\n\\n### Social Media\\n\\nWe follow major technical communities and social media platforms and respond promptly to user feedback:\\n- **Technical blog**: regular technical articles and project updates\\n- **Social media**: share project news and usage cases\\n- **Technical conferences**: participate in industry events to share engineering practice\\n\\n### Community Goals\\n\\nWe aim to achieve the following goals through the open-source community:\\n\\n1. **Technology democratization**: enable more developers to use advanced context engineering technologies\\n2. **Innovation acceleration**: accelerate innovation and product iteration through collaboration\\n3. **Standards building**: promote technical standards and best practices in context engineering\\n4. **Talent development**: cultivate more talent in the context engineering field\\n\\n### Open Collaboration\\n\\nOpenViking welcomes collaboration from developers, research institutions, and companies. We look forward to:\\n\\n- **Technical collaboration**: deep technical cooperation with academia and industry\\n- **Ecosystem integration**: establish integrations with related open-source projects and commercial products\\n- **Application promotion**: jointly promote the application of context engineering technologies across more scenarios\\n\\n---\\n\\n**Join us to build the context infrastructure for the AI Agent era!**\\n"},"headers":[],"relativePath":"en/about/01-about-us.md","filePath":"en/about/01-about-us.md","lastUpdated":1777024806000}'),s={name:"en/about/01-about-us.md"};function c(l,e,d,u,p,g){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="openviking-team-and-organization" tabindex="-1">OpenViking Team and Organization <a class="header-anchor" href="#openviking-team-and-organization" aria-label="Permalink to &quot;OpenViking Team and Organization&quot;">​</a></h1><h2 id="project-overview" tabindex="-1">Project Overview <a class="header-anchor" href="#project-overview" aria-label="Permalink to &quot;Project Overview&quot;">​</a></h2><p>OpenViking is an open-source context database initiated and maintained by ByteDance’s Volcano Engine Viking team, dedicated to building robust context engineering infrastructure for the AI Agent ecosystem. As a new-generation context database, OpenViking provides a unified data abstraction layer, an intelligent semantic parsing engine, and a high-performance hybrid retrieval system to deliver reliable backend support for all kinds of AI applications.</p><h2 id="team-introduction" tabindex="-1">Team Introduction <a class="header-anchor" href="#team-introduction" aria-label="Permalink to &quot;Team Introduction&quot;">​</a></h2><h3 id="viking-team-background" tabindex="-1">Viking Team Background <a class="header-anchor" href="#viking-team-background" aria-label="Permalink to &quot;Viking Team Background&quot;">​</a></h3><p>The Viking team belongs to ByteDance’s Volcano Engine and focuses on unstructured information processing and intelligent retrieval. The team brings together dozens of seasoned experts across distributed systems, machine learning, data engineering, and AI algorithms, with extensive commercial experience in context engineering.</p><h4 id="core-technical-capabilities" tabindex="-1">Core Technical Capabilities <a class="header-anchor" href="#core-technical-capabilities" aria-label="Permalink to &quot;Core Technical Capabilities&quot;">​</a></h4><p><strong>Large-Scale Vector Retrieval System</strong></p><ul><li>Supports real-time retrieval and similarity computation over hundreds of millions of vectors</li><li>Delivers millisecond-level latency to meet high-concurrency business scenarios</li><li>Supports hybrid retrieval strategies combining semantic similarity and keyword matching</li></ul><p><strong>Multimodal Content Understanding Engine</strong></p><ul><li>Supports intelligent parsing for text, images, audio, video, and more</li><li>Achieves cross-modal semantic association and content understanding</li><li>Provides unified content abstraction and semantic representation</li></ul><p><strong>Distributed System Architecture Design</strong></p><ul><li>Extensive experience building highly available, scalable distributed systems</li><li>Supports elastic scaling and automatic failure recovery</li><li>Balances data consistency and system performance</li></ul><h3 id="development-history-and-technical-evolution" tabindex="-1">Development History and Technical Evolution <a class="header-anchor" href="#development-history-and-technical-evolution" aria-label="Permalink to &quot;Development History and Technical Evolution&quot;">​</a></h3><p>The Viking team’s exploration in context engineering reflects our commitment to continuous innovation and industry impact. As AI Agent applications rapidly evolve, we plan to use OpenViking as a public verification platform for new concepts and approaches, building in the open together with the community to create a responsible AI application stack.</p><table tabindex="0"><thead><tr><th>Time Period</th><th>Milestone</th><th>Technical Breakthroughs and Industry Impact</th></tr></thead><tbody><tr><td><strong>2019–2023</strong></td><td>VikingDB vector database widely adopted inside ByteDance</td><td>Powered multiple core products’ unstructured information retrieval; accumulated engineering experience in large-scale vector retrieval; validated the technical value of vector databases in real-world business scenarios</td></tr><tr><td><strong>2024</strong></td><td>Released developer-facing product matrix: VikingDB, Viking Knowledge Base, Viking Memory Base</td><td>Officially provided on Volcano Engine public cloud; successfully supported thousands of enterprise customers building AI-native applications; marked the successful transition from internal tooling to commercial products</td></tr><tr><td><strong>2025</strong></td><td>Expanded to upper-layer applications such as AI Search and Knowledge Assistants</td><td>Built a complete product matrix from infrastructure to application layer; further validated business value across scenarios; formed a full loop from technology to product</td></tr><tr><td><strong>Late 2025</strong></td><td>Open-sourced <a href="https://github.com/volcengine/MineContext" target="_blank" rel="noreferrer">MineContext</a> project</td><td>Explored proactive AI application patterns; validated personal context engineering ideas; accumulated community operation experience for OpenViking</td></tr><tr><td><strong>Early 2026</strong></td><td>Open-sourced OpenViking project</td><td>Released a newly designed context database architecture for the global AI Agent ecosystem; marked the strategic shift from commercial product provider to open-source contributor</td></tr></tbody></table><h3 id="academic-collaboration-and-industry–academia-integration" tabindex="-1">Academic Collaboration and Industry–Academia Integration <a class="header-anchor" href="#academic-collaboration-and-industry–academia-integration" aria-label="Permalink to &quot;Academic Collaboration and Industry–Academia Integration&quot;">​</a></h3><p>Since its inception, OpenViking has established deep academic collaborations with top universities and research institutes worldwide to jointly explore context database design paradigms and best engineering practices for the AI era. This industry–academia collaboration ensures technological advancement while staying closely aligned with real application needs.</p><p>We sincerely thank the following scholars for their contributions and guidance in launching OpenViking:</p><ul><li>Associate Professor Sun Yahui, School of Information, Renmin University of China</li><li>Professor Gao Yunjun, School of Software, Zhejiang University; Researchers Zhu Yifan and Ge Congcong</li><li>Associate Professor Dai Guohao, School of Artificial Intelligence, Shanghai Jiao Tong University; Co‑founder and Chief Scientist of Wuwen Xinqiong</li></ul><p>Our collaboration models include:</p><ul><li><strong>Joint research projects</strong>: conduct frontier research in context engineering</li><li><strong>Technical workshops</strong>: organize regular academic exchanges and technical reviews</li><li><strong>Talent cultivation</strong>: provide practice platforms and research topics for graduate students</li><li><strong>Technology transfer</strong>: transform academic findings into engineering best practices</li></ul><h2 id="open-source-organization" tabindex="-1">Open-Source Organization <a class="header-anchor" href="#open-source-organization" aria-label="Permalink to &quot;Open-Source Organization&quot;">​</a></h2><h3 id="project-development-stages" tabindex="-1">Project Development Stages <a class="header-anchor" href="#project-development-stages" aria-label="Permalink to &quot;Project Development Stages&quot;">​</a></h3><p>OpenViking is currently in its early development stage. We divide development into three key phases:</p><ul><li><p>Phase 1: Foundation building Focus on constructing solid technical foundations after open-sourcing, including core protocols, interfaces, AI Agent facilities, and providing a reliable minimal implementation.</p></li><li><p>Phase 2: Ecosystem expansion Build a plugin ecosystem, support third-party feature extensions, drive deep integration with mainstream AI frameworks and tools, and extend enterprise-grade capabilities to meet large-scale deployment needs.</p></li><li><p>Phase 3: Industry adoption Establish industry technical standards and best practices, build certification systems and partner ecosystems, and promote broader real-world adoption of context engineering.</p></li></ul><h3 id="governance-structure-and-decision-making" tabindex="-1">Governance Structure and Decision-Making <a class="header-anchor" href="#governance-structure-and-decision-making" aria-label="Permalink to &quot;Governance Structure and Decision-Making&quot;">​</a></h3><p>Based on the project’s long-term roadmap, we are establishing a layered governance structure:</p><h4 id="open-source-governance-committee" tabindex="-1">Open-Source Governance Committee <a class="header-anchor" href="#open-source-governance-committee" aria-label="Permalink to &quot;Open-Source Governance Committee&quot;">​</a></h4><p>OpenViking is guided by a professional governance committee responsible for overall strategic planning and technical decisions. The committee consists of core contributors and domain experts, with responsibilities including:</p><p><strong>Strategic Planning</strong></p><ul><li>Define the long-term technical roadmap and vision</li><li>Set release plans and feature priorities</li><li>Evaluate the long-term impact of technical decisions on the ecosystem</li></ul><p><strong>Technical Governance</strong></p><ul><li>Establish and maintain code quality standards and engineering norms</li><li>Review core architecture changes and major feature implementations</li><li>Ensure sustainability and backward compatibility</li></ul><p><strong>Community Development</strong></p><ul><li>Define community development strategy and contributor growth paths</li><li>Organize technical exchange activities and developer conferences</li><li>Build incentive mechanisms and recognition systems</li></ul><p><strong>Ecosystem Collaboration</strong></p><ul><li>Establish technical cooperation with related open-source projects</li><li>Promote integration and certification with commercial products</li><li>Manage intellectual property and license compliance</li></ul><h4 id="committee-core-members" tabindex="-1">Committee Core Members <a class="header-anchor" href="#committee-core-members" aria-label="Permalink to &quot;Committee Core Members&quot;">​</a></h4><p>Current core members of the governance committee: Haojie Qin, Jiahui Zhou, Linggang Wang, Maojia Sheng, Yaohui Sun</p><p>To ensure openness and diversity, we welcome eligible community contributors to join the committee through future nomination and election procedures.</p><h2 id="community-participation" tabindex="-1">Community Participation <a class="header-anchor" href="#community-participation" aria-label="Permalink to &quot;Community Participation&quot;">​</a></h2><h3 id="join-the-community" tabindex="-1">Join the Community <a class="header-anchor" href="#join-the-community" aria-label="Permalink to &quot;Join the Community&quot;">​</a></h3><p>We warmly invite developers worldwide to join the OpenViking community and co-build next-generation context engineering infrastructure. You can participate in the following ways:</p><h4 id="instant-messaging" tabindex="-1">Instant Messaging <a class="header-anchor" href="#instant-messaging" aria-label="Permalink to &quot;Instant Messaging&quot;">​</a></h4><h5 id="lark-group" tabindex="-1">Lark Group <a class="header-anchor" href="#lark-group" aria-label="Permalink to &quot;Lark Group&quot;">​</a></h5><p>Scan the QR code below to join the Lark group and communicate with the core development team in real time:</p><p><img src="'+n+'" alt="Join via Lark QR"></p><p><em>Note: Please ensure you have installed the <a href="https://www.feishu.cn/" target="_blank" rel="noreferrer">Lark client</a> before joining.</em></p><h5 id="wechat-group" tabindex="-1">WeChat Group <a class="header-anchor" href="#wechat-group" aria-label="Permalink to &quot;WeChat Group&quot;">​</a></h5><p>Scan the QR code below to add the assistant on WeChat, mention &quot;OpenViking&quot; and you will be invited to the WeChat group:</p><p><img src="'+i+'" alt="Join via WeChat QR"></p><p><strong>Discord</strong></p><p><a href="https://discord.com/invite/eHvx8E9XF3" target="_blank" rel="noreferrer">Join our Discord Server</a></p><p><strong>X</strong></p><p><a href="https://x.com/openvikingai" target="_blank" rel="noreferrer">Follow us on X</a></p><h3 id="ways-to-participate" tabindex="-1">Ways to Participate <a class="header-anchor" href="#ways-to-participate" aria-label="Permalink to &quot;Ways to Participate&quot;">​</a></h3><p>We provide multiple participation channels to meet different collaboration needs:</p><h4 id="_1-code-contributions" tabindex="-1">1. Code Contributions <a class="header-anchor" href="#_1-code-contributions" aria-label="Permalink to &quot;1. Code Contributions&quot;">​</a></h4><ul><li><strong>Submit Issues</strong>: report bugs, propose features, or discuss technical solutions</li><li><strong>Submit Pull Requests</strong>: contribute code improvements, documentation updates, or test cases</li><li><strong>Code Review</strong>: participate in reviews to improve code quality</li></ul><h4 id="_2-documentation-contributions" tabindex="-1">2. Documentation Contributions <a class="header-anchor" href="#_2-documentation-contributions" aria-label="Permalink to &quot;2. Documentation Contributions&quot;">​</a></h4><ul><li><strong>Improve documentation</strong>: enhance user guides, API docs, or tutorials</li><li><strong>Translation support</strong>: help translate documentation into other languages</li><li><strong>Example code</strong>: provide usage examples and best practices</li></ul><h4 id="_3-community-support" tabindex="-1">3. Community Support <a class="header-anchor" href="#_3-community-support" aria-label="Permalink to &quot;3. Community Support&quot;">​</a></h4><ul><li><strong>Technical sharing</strong>: share experiences and technical insights</li><li><strong>Q&amp;A</strong>: help other developers solve usage problems</li><li><strong>Ecosystem building</strong>: promote integration of OpenViking with other open-source projects</li></ul><h4 id="_4-ecosystem-expansion" tabindex="-1">4. Ecosystem Expansion <a class="header-anchor" href="#_4-ecosystem-expansion" aria-label="Permalink to &quot;4. Ecosystem Expansion&quot;">​</a></h4><ul><li><strong>Plugin development</strong>: develop third-party plugins or feature extensions</li><li><strong>Integration adaptation</strong>: drive deep integration with mainstream frameworks</li><li><strong>Application cases</strong>: share real-world adoption experiences</li></ul><h2 id="discussion-and-collaboration" tabindex="-1">Discussion and Collaboration <a class="header-anchor" href="#discussion-and-collaboration" aria-label="Permalink to &quot;Discussion and Collaboration&quot;">​</a></h2><h3 id="official-channels" tabindex="-1">Official Channels <a class="header-anchor" href="#official-channels" aria-label="Permalink to &quot;Official Channels&quot;">​</a></h3><h4 id="github-platform" tabindex="-1">GitHub Platform <a class="header-anchor" href="#github-platform" aria-label="Permalink to &quot;GitHub Platform&quot;">​</a></h4><ul><li><strong>Issues</strong>: feature suggestions, bug reports, and technical discussions</li><li><strong>Pull Requests</strong>: code contributions and documentation updates</li><li><strong>Discussions</strong>: design discussions and community exchange</li></ul><h4 id="repository" tabindex="-1">Repository <a class="header-anchor" href="#repository" aria-label="Permalink to &quot;Repository&quot;">​</a></h4><ul><li><strong>Main repository</strong>: <code>https://github.com/volcengine/openviking</code></li><li><strong>Issue tracking</strong>: <code>https://github.com/volcengine/openviking/issues</code></li></ul><h3 id="real-time-communication" tabindex="-1">Real-Time Communication <a class="header-anchor" href="#real-time-communication" aria-label="Permalink to &quot;Real-Time Communication&quot;">​</a></h3><h4 id="lark-group-1" tabindex="-1">Lark Group <a class="header-anchor" href="#lark-group-1" aria-label="Permalink to &quot;Lark Group&quot;">​</a></h4><ul><li><strong>Technical discussion</strong>: real-time technical exchange and Q&amp;A</li><li><strong>Code review</strong>: fast feedback and collaborative development</li><li><strong>Event notice</strong>: community activities and technical sharing</li></ul><h3 id="social-media" tabindex="-1">Social Media <a class="header-anchor" href="#social-media" aria-label="Permalink to &quot;Social Media&quot;">​</a></h3><p>We follow major technical communities and social media platforms and respond promptly to user feedback:</p><ul><li><strong>Technical blog</strong>: regular technical articles and project updates</li><li><strong>Social media</strong>: share project news and usage cases</li><li><strong>Technical conferences</strong>: participate in industry events to share engineering practice</li></ul><h3 id="community-goals" tabindex="-1">Community Goals <a class="header-anchor" href="#community-goals" aria-label="Permalink to &quot;Community Goals&quot;">​</a></h3><p>We aim to achieve the following goals through the open-source community:</p><ol><li><strong>Technology democratization</strong>: enable more developers to use advanced context engineering technologies</li><li><strong>Innovation acceleration</strong>: accelerate innovation and product iteration through collaboration</li><li><strong>Standards building</strong>: promote technical standards and best practices in context engineering</li><li><strong>Talent development</strong>: cultivate more talent in the context engineering field</li></ol><h3 id="open-collaboration" tabindex="-1">Open Collaboration <a class="header-anchor" href="#open-collaboration" aria-label="Permalink to &quot;Open Collaboration&quot;">​</a></h3><p>OpenViking welcomes collaboration from developers, research institutions, and companies. We look forward to:</p><ul><li><strong>Technical collaboration</strong>: deep technical cooperation with academia and industry</li><li><strong>Ecosystem integration</strong>: establish integrations with related open-source projects and commercial products</li><li><strong>Application promotion</strong>: jointly promote the application of context engineering technologies across more scenarios</li></ul><hr><p><strong>Join us to build the context infrastructure for the AI Agent era!</strong></p>',86)])])}const f=t(s,[["render",c]]);export{b as __pageData,f as default};
